def f(n: int) -> str:
    """Convert an integer (1‑3999) to a Roman numeral."""
    if not (1 <= n <= 3999):
        raise ValueError("n must be between 1 and 3999")
    vals = [
        (1000, "M"), (900, "CM"), (500, "D"), (400, "CD"),
        (100, "C"), (90, "XC"), (50, "L"), (40, "XL"),
        (10, "X"), (9, "IX"), (5, "V"), (4, "IV"),
        (1, "I")
    ]
    res = []
    for value, numeral in vals:
        count, n = divmod(n, value)
        res.append(numeral * count)
        if n == 0:
            break
    return "".join(res)
